use serde::{Deserialize, Serialize};

#[derive(Serialize, Deserialize)]
struct ProofMessage {
    ok: bool,
    source: &'static str,
    checksum: u64,
}

#[derive(Serialize, Deserialize)]
struct ProofRecord0 {
    id: u64,
    label: &'static str,
    values: [u32; 8],
}

fn proof_record_0() -> u64 {
    let record = ProofRecord0 {
        id: 0u64,
        label: "cinder-proof",
        values: [1, 2, 3, 4, 5, 6, 7, 8],
    };

    record.id + record.values.iter().map(|value| *value as u64).sum::<u64>()
}

